const Q_GEOGRAPHY_2013=[{"id": "objective>Geography>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">English</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Geography</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject being referred to in this context is Geography. This is inferred from the category of the question, which is 'objective>Geography>2013>1'. Therefore, the correct answer is Geography.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The likely occupation of the people in the area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market gardening </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farming</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Presence of rivers(fishing), scattered cultivation & palms all indicate farming.</div>", "topic": "REGIONAL GEOGRAPHY : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> River Yoo flow toward the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">east</div>", "<div style=\"font-family:Cambria;font-size:17px;\">west </div>", "<div style=\"font-family:Cambria;font-size:17px;\">southwest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">southeast</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The continuos river reduces in value west-ward. River Yoo flow toward the west</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The beraing of Jodo from Joyo is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">270<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">280<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">315<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">340<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">270°(The first 3 quadrants) + 65° = 335° <br/> The beraing of Jodo from Joyo is 340<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the map is enlarged twice, the new scale would be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:100,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:125,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/200,000 × 2/1 = 1/100,000 <br/> If the map is enlarged twice, the new scale would be 1:100,000</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The annual range of temperature of Delhi is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">35° - 15° = 20° <br/> The annual range of temperature of Delhi is 20°</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The climate can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equatorial climate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical monsoon climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical marine climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equatorial monsoon climate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a low annual rainfall with high temperature.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of a closed traverse is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the compass is read at each point in turn and as a check back bearings are taken </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the compass is read and forward bearings are taken</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the compass is read at each point and plotted as a check </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the compass is read at each point and turned back at each point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A closed traverse in surveying is a series of connected lines, the first and last of which join in a point, forming a closed circuit. The principle of a closed traverse is that the compass is read at each point in turn and as a check, back bearings are taken. This is done to ensure the accuracy of the survey. Back bearings are the opposite direction of the forward bearings and are used to check the accuracy of the survey.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equatorial circumference of the earth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20084km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30,084km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40,084km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.084km</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equatorial circumference of the Earth is approximately 40,075 kilometers. This is the distance around the Earth at the equator. The closest option to this value is 40,084km.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following rocks is suitable for the construction of roads and building purposes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Basalt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Graphite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Granite is a type of igneous rock that is very hard and durable, making it suitable for construction purposes such as roads and buildings. It is resistant to weathering and can bear significant weight, making it ideal for such uses. Limestone can also be used in construction, but it is not as durable as granite. Basalt is also a hard rock but it is not commonly used in construction. Graphite is a form of carbon and is not suitable for construction.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mountains formed as a result of compressional forces are known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Block Mountains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fold Mountains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Residual Mountains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic Mountains</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fold Mountains are formed as a result of compressional forces. When the Earth's crust is subjected to compressional forces, it buckles and folds, creating Fold Mountains. This process is known as orogeny.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The feature marked X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a waterfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a plunge pool</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an eroded debris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bedrock</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When water undercuts the softer rock layer at the base of the water, the water fall forms a plunge pool.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature marked Q is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parent material</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soft rock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hard rock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erratic block</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In water fall formation, top layer is always hard rock but underlaid immediately with soft rock.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mediterranean Sea has a higher salinity than the oceans because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the surrounding soils are salty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is low rainfall in the region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the area has a higher temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of dead animal fossils</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mediterranean Sea has a higher salinity than the oceans because there is low rainfall in the region. Salinity refers to the saltiness or dissolved salt content of a body of water. In regions with low rainfall, there is less freshwater to dilute the salt, leading to higher salinity.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sun-dial is used for recording the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amount of sunshine in a place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duration of sunshine in a place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">position of the sun in a place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensity of sunshine within a period of time</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sun-dial is a device that tells the time of day by the apparent position of the Sun in the sky. In the narrowest sense of the word it will consists of a flat plate, the dial and a gnomon which will throw a shadow onto the surface; lines marked onto the surface will indicate the time of day.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The actual amount of water vapour present in the air which is expressed in grams per cubic metre is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">humidity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">actual humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absolute humidity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The actual amount of water vapour present in the air which is expressed in grams per cubic metre is referred to as absolute humidity. Absolute humidity is a measure of the actual amount of water vapour in a particular sample of air: measured in grams per cubic metre. The other options refer to different aspects of humidity. Relative humidity, for example, is the ratio of the current absolute humidity to the highest possible absolute humidity.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pine, fir, larch and spruce are commonly found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deciduous forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equatorial forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coniferous forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mangrove forest</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pine, fir, larch and spruce are commonly found in coniferous forests. Coniferous forests are predominantly evergreen trees that bear cones, with needles rather than leaves. Deciduous forests are made up of trees that lose their leaves in the fall, equatorial forests are tropical rainforests found near the equator, and mangrove forests are found in coastal areas where the soil is loose and waterlogged.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major components of soil are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">organic matter, texture, structure and air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">texture, organic matter, water and air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water, air, mineral and organic matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water, texture, nutrients and mineral</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water, air, mineral and organic matter are major components. Soil texture and structure are properties and not components.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil forming process in the hot, humid tropics where rainfall and temperature are high throughout the year is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">laterization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">podzolization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the only process of land formation in the hot humid region. Podzolization occurs in humid temperatures while calcification and salinization for desert and semi-desert.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an atmosphere resource is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petroleum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An atmospheric resource is a resource that is derived from the atmosphere. Water, in the form of rainfall, is an example of an atmospheric resource. It is a renewable resource that is replenished by the water cycle, which includes evaporation, condensation, and precipitation.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Igneous rocks are different from sedimentary rocks by their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appearance and origin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shape and size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">density and appearance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">area and density</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Igneous rocks and sedimentary rocks are primarily differentiated by their origin and appearance. Igneous rocks are formed from the cooling and solidification of magma or lava, while sedimentary rocks are formed from the accumulation of sediments. This difference in formation leads to distinct differences in their appearance. For example, igneous rocks often have a crystalline structure due to the slow cooling of magma, while sedimentary rocks often have layers due to the deposition of sediments over time.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The massive removal of trees and forest cover without replacement is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">afforestation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deforestation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush clearing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush burning</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deforestation refers to the process of clearing a wide area of trees. It is the removal or clearing of a forest or stand of trees where the land is thereafter converted to a non-forest use. This is different from afforestation which is the process of establishing a forest, or stand of trees, in an area where there was no forest. Bush clearing and bush burning do not necessarily involve the removal of trees and forest cover without replacement.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The total population of a country can be obtained from its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sample survey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birth and death rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national census</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National census is the process of counting per head every human in a particular are usually at the interval of about 10 years.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most significant way the components of ecosystem can be identified is that, there must be a degree of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reciprocal inter-relationship existing among them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent inter-relationship existing among them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">complexity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adaptation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Every component of an ecosystem has a degree of complexity.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factor that affected the growth of the population of Africa during the pre-colonial times</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Inter-tribal wars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Famine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Epidemics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Natural Hazards</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pre-colonial times was a period of restless inter-tribal wars as a result of struggle for ethnic survival.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following terms relates population size of land?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Census</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intensity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Demography</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Density is the number of people living in an area per time divided by the land area i.e person/km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The problems of unemployment, housing, traffic congestion and environmental degradation are associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slums</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urbanization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political disturbances</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Areas of old low housing where living and social conditions.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rural settlements are important to urban centres because they provide </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">road </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transport </div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rural settlements are important to urban centres because they provide labour. Rural areas are often the source of the workforce that migrates to urban areas for better job opportunities. This is not to say that rural areas do not also provide other resources such as food and raw materials, but in the context of the options provided, labour is the most accurate answer.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Settlements that develop along communication routes are likely to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oval </div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Settlements that develop along communication routes are likely to be linear. This is because the development of settlements is often influenced by the availability and accessibility of transportation and communication routes. When a settlement develops along a road, railway, or river, it often takes on a linear shape, following the path of the route.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest advantage of road transportation over other modes is that the former is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheaper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more flexible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less risky</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faster</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest advantage of road transportation over other modes is that it is more flexible. Road transportation allows for door-to-door or street-to-street services, which air, rail, and water transportation cannot provide. This flexibility makes it possible to deliver goods and services directly to specific locations, making it a preferred mode of transportation for many businesses and individuals.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best breeds of dairy cattle can be found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">South America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Asia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Australia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Europe</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The best breeds of dairy cattle can be found in Europe. This is because Europe has a long history of dairy farming and has developed several high producing dairy breeds such as the Holstein, Jersey, and Guernsey.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest benefit of mixed farming is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is very cheap to practise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the animals produce the manure for crop production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it combines the advantage of crop and animal husbandary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the animals feed from crop farming</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since mixed farming is the cultivation of crops and rearing of animals, it combines the benefits of the two.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the busiest and most important world shipping route?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The South Atlantic route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Cape route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The North Atlantic route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Panama Canal route</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the route that connects the two most industrialized places in the world; Western Europe and Eastern USA.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of countries is a major producer of rubber?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Liberia and Indonesia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Indonesia, Malaysia and Zimbabwe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Niger and Liberia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa, Liberia and China</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Liberia, and Indonesia are among the world's largest producers of rubber. Malaysia and Indonesia, in particular, are known for their vast rubber plantations. Liberia also has a significant rubber industry, with Firestone Liberia being one of the largest rubber plantations in the world.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest industrial areas of the world are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Africa and the Caribbean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Ruhr industrial region and South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Europe and the United States of America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan and Australia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest industrial areas of the world are indeed in Western Europe and the United States of America. These regions have a high concentration of industries due to their advanced economies, technological capabilities, and infrastructure. The Ruhr region in Germany, for example, is one of the most industrialized areas in Europe, while the United States has numerous industrial hubs such as the Rust Belt.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Obudu Plateau is noted for its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tsetsefly infestation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hot climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cattle ranch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">waterfalls</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Obudu Plateau is noted for its cattle ranch. The Obudu Cattle Ranch, now known as the Obudu Mountain Resort, is one of the most beautiful tourist destinations in Nigeria. It was developed in 1951 and is a popular destination for its beautiful landscapes, serene environment, and cool climate.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Livestock rearing in Nigeria is still predominantly the occupation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">small holder farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sedentary rearers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large-scale farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nomadic herders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Livestock rearing in Nigeria is predominantly the occupation of nomadic herders. Nomadic herding is a form of pastoralism where livestock are herded in order to find fresh pastures on which to graze. This is often the case in regions where the quality of the soil or the climate makes it impossible to grow crops consistently.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the highest concentration of industries in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kano </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Port-Harcourt</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is considered to be the commercial and industrial capital of Nigeria and that is a reason it is the most populous state.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The location of a cement industry in Ewekoro, Nigeria is largely influenced  by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nearness to source of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequate transportation facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government policy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The location of a cement industry in Ewekoro, Nigeria is largely influenced by nearness to raw materials. Cement production requires limestone and clay, and these materials are heavy and expensive to transport. Therefore, cement factories are often located near the source of these raw materials to reduce transportation costs.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The soil type found in the area marked S is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterite soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alluvial soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loamy soil</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the presence of the lake, the soil is of alluvial deposit.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area marked T is rich in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The area is Shagamu/Ewekoro in Ogun State. The area marked T is rich in limestone</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following winds is responsible for the dry season in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tropical maritime airmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical continental airmass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equatorial easterlies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Harmattan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is beacuse it originates from the high pressure belt of hoarse latitude and blows southwards, it picks up dust in Sahara desert and becomes dry, dusty , cold and hazy.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area marked K represents what type of vegetation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Savannah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warm temperate forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The belt immediately after equatorial/tropical rainforest is the tropical savanna both north and south of the forest.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area marked Y is known for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shifting cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensive subsistence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hunting and fishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nomadic herding</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From Northern Nigeria northward to North Africa is the home of nomadic herdsmen, searching for grass and water in the desert.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups is known for nomadic grazing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Masai of Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Akans of Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hausas of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Arabs of Algeria</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Masai of Kenya are known for their practice of pastoralism, which involves the keeping and herding of livestock. They are a Nilotic ethnic group in East Africa.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries has gold as its major foreign exchange earner?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tanzania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South Africa is the world's largest producer of gold and is estimated to have half of the gold resources in the world. The mining sector, including gold mining, is a major part of the country's economy.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is largest  country in West Africa?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It has a land area of 1,204 km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. Niger is the largest  country in West Africa </div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area marked P is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zambia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Swaziland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lesotho</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Botswana</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It borders with Namibia in the west, Angola and Zambia in the north, Zimbabwe in the east and South Africa in the south.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area marked Q is best known for mining of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uranium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">platinum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South Africa is the world's largest producer of platinum.</div>", "topic": "PRATICAL GEOGRAPHY II : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following rivers is an inland drainage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">River Hadejia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Nile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Senegal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Volta</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It flows into Lake Chad and not the ocean. River Hadejia is an inland drainage.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}];
